              {r.bear_read && <div style={{ marginTop:4, fontSize:12, color:C.red }}>Bear: {r.bear_read}</div>}
              <div style={{ marginTop:7, fontSize:12.5, color:C.text }}>Posture: {r.action_posture||"Hold; no add until the split resolves."}</div>
